import React, { useState, useEffect } from 'react';
// eslint-disable-next-line no-unused-vars
import { Link } from 'react-router-dom';
import { getAllPayments, verifyPayment } from '../../services/dataService';
import { formatDate, formatCurrency } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiCheck, FiX, FiSearch } from 'react-icons/fi';

const AdminPayments = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [actionModal, setActionModal] = useState({ show: false, payment: null, action: '' });
  const [remarks, setRemarks] = useState('');

  useEffect(() => { fetchPayments(); }, []);

  const fetchPayments = async () => {
    try {
      const res = await getAllPayments();
      setPayments(res.data.data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleVerify = async (id, status) => {
    try {
      await verifyPayment(id, { status, adminRemarks: remarks });
      setActionModal({ show: false, payment: null, action: '' });
      setRemarks('');
      fetchPayments();
    } catch (err) { console.error(err); }
  };

  const filtered = payments.filter(p => {
    const matchFilter = filter === 'all' || p.status === filter;
    const matchSearch = !search || p.customer?.name?.toLowerCase().includes(search.toLowerCase()) || p.property?.title?.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  const totalVerified = payments.filter(p => p.status === 'verified').reduce((s, p) => s + p.amount, 0);
  const totalPending = payments.filter(p => p.status === 'pending').reduce((s, p) => s + p.amount, 0);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header"><h1>Payment Management</h1></div>

      <div className="stats-grid" style={{ marginBottom: '24px' }}>
        <div className="stat-card"><div className="stat-value">{formatCurrency(totalVerified)}</div><div className="stat-label">Total Verified</div></div>
        <div className="stat-card"><div className="stat-value">{formatCurrency(totalPending)}</div><div className="stat-label">Pending Verification</div></div>
        <div className="stat-card"><div className="stat-value">{payments.length}</div><div className="stat-label">Total Payments</div></div>
      </div>

      <div className="filters-bar">
        <div className="search-box"><FiSearch /><input type="text" placeholder="Search..." value={search} onChange={(e) => setSearch(e.target.value)} /></div>
        {['all', 'pending', 'verified', 'rejected'].map(f => (
          <button key={f} className={`btn btn-sm ${filter === f ? 'btn-primary' : 'btn-outline'}`} onClick={() => setFilter(f)}>
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="empty-state"><p>No payments found</p></div>
      ) : (
        <div className="table-container">
          <table>
            <thead><tr><th>Customer</th><th>Property</th><th>Total Plan</th><th>Term Payment</th><th>Status</th><th>Term</th><th>Remaining Balance</th><th>Method</th><th>Date</th><th>Actions</th></tr></thead>
            <tbody>
              {filtered.map(p => (
                <tr key={p._id}>
                  <td><strong>{p.customer?.name || 'N/A'}</strong></td>
                  <td>{p.property?.title || 'N/A'}</td>
                  <td>
                    {p.installmentOption === '3x' ? (
                      <strong>{formatCurrency(p.totalInstallmentAmount)}</strong>
                    ) : (
                      <strong>{formatCurrency(p.amount)}</strong>
                    )}
                  </td>
                  <td>{formatCurrency(p.amount)}</td>
                  <td><StatusBadge status={p.status} /></td>
                  <td>
                    {p.installmentOption === '3x' ? (
                      <span className="badge" style={{ backgroundColor: '#0066cc', color: 'white', padding: '4px 8px', borderRadius: '4px' }}>
                        Term {p.installmentTerm}/3
                      </span>
                    ) : (
                      <span className="badge" style={{ backgroundColor: '#28a745', color: 'white', padding: '4px 8px', borderRadius: '4px' }}>
                        Full
                      </span>
                    )}
                  </td>
                  <td>
                    {p.remainingBalance > 0 ? (
                      <div>
                        <p style={{ margin: 0, color: '#dc3545', fontWeight: 'bold' }}>{formatCurrency(p.remainingBalance)}</p>
                        {p.installmentOption === '3x' && p.status === 'pending' && (
                          <small style={{ color: '#666' }}>
                            {p.installmentTerm === 2 ? 'Term 2 + Term 3' : 'Term 3'}
                          </small>
                        )}
                      </div>
                    ) : (
                      <span>-</span>
                    )}
                  </td>
                  <td>{p.paymentMethod?.replace('_', ' ')}</td>
                  <td>{formatDate(p.createdAt)}</td>
                  <td>
                    {p.status === 'pending' && (
                      <div className="btn-group">
                        <button className="btn btn-sm btn-success" onClick={() => setActionModal({ show: true, payment: p, action: 'verified' })}><FiCheck /></button>
                        <button className="btn btn-sm btn-danger" onClick={() => setActionModal({ show: true, payment: p, action: 'rejected' })}><FiX /></button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {actionModal.show && (
        <div className="modal-overlay" onClick={() => setActionModal({ show: false, payment: null, action: '' })}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3>{actionModal.action === 'verified' ? 'Verify' : 'Reject'} Payment</h3>
            <div className="alert alert-info" style={{ marginBottom: '16px' }}>
              <p><strong>Customer:</strong> {actionModal.payment?.customer?.name}</p>
              <p><strong>Property:</strong> {actionModal.payment?.property?.title}</p>
              <p><strong>Term Payment Amount:</strong> {formatCurrency(actionModal.payment?.amount)}</p>
              {actionModal.payment?.installmentOption === '3x' && (
                <>
                  <p><strong>Payment Plan:</strong> Term {actionModal.payment?.installmentTerm}/3</p>
                  <p><strong>Total Plan Amount:</strong> {formatCurrency(actionModal.payment?.totalInstallmentAmount)}</p>
                  <p style={{ color: '#dc3545' }}><strong>Remaining Balance After This:</strong> {formatCurrency(actionModal.payment?.remainingBalance)}</p>
                </>
              )}
            </div>
            <div className="form-group" style={{ marginTop: '12px' }}>
              <label>Remarks</label>
              <textarea className="form-control" value={remarks} onChange={(e) => setRemarks(e.target.value)} rows="3" />
            </div>
            <div className="btn-group" style={{ marginTop: '16px' }}>
              <button className={`btn ${actionModal.action === 'verified' ? 'btn-success' : 'btn-danger'}`} onClick={() => handleVerify(actionModal.payment._id, actionModal.action)}>
                {actionModal.action === 'verified' ? 'Verify' : 'Reject'}
              </button>
              <button className="btn btn-secondary" onClick={() => { setActionModal({ show: false, payment: null, action: '' }); setRemarks(''); }}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPayments;
